// useAuthGate.ts
import {router} from 'expo-router';
import {MMKV} from 'react-native-mmkv';
const storage = new MMKV();
export function gateAuth(intendedPath: string, isAuthed: boolean) { if (!isAuthed) { storage.set('intendedPath', intendedPath); router.replace('/auth'); }}
export function afterAuth() { const path = storage.getString('intendedPath'); if (path) { storage.delete('intendedPath'); router.replace(path); } else router.replace('/'); }

