// FitnessBrandSplash.tsx
import React, {useEffect} from 'react';
import {StyleSheet, View, Pressable, useWindowDimensions} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withTiming, runOnJS} from 'react-native-reanimated';
import {SplashScreen, router} from 'expo-router';
import {LogoMark} from './LogoMark';
import {ECGLine} from './ECGLine';
import {Audio} from 'expo-av';
import * as Haptics from 'expo-haptics';
SplashScreen.preventAutoHideAsync();

export function FitnessBrandSplash({onComplete}: {onComplete: () => void}) {
  const {width: SW} = useWindowDimensions();
  const logoScale = useSharedValue(0);
  const ecgOpacity = useSharedValue(0);
  const dismiss = () => { onComplete(); SplashScreen.hideAsync(); };
  useEffect(() => { logoScale.value = withSpring(1, {damping: 14, stiffness: 200}); ecgOpacity.value = withTiming(1, {duration: 600}); Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success); (async () => { try { const {sound} = await Audio.Sound.createAsync(require('./assets/heartbeat.mp3')); await sound.playAsync(); } catch {}})(); const t = setTimeout(() => { dismiss(); }, 1500); return () => clearTimeout(t); }, []);
  const logoStyle = useAnimatedStyle(() => ({transform: [{scale: logoScale.value}]}));
  const ecgStyle = useAnimatedStyle(() => ({opacity: ecgOpacity.value}));
  return (<Pressable onPress={dismiss} style={s.root}><Animated.View style={logoStyle}><LogoMark size={Math.min(SW * 0.4, 200)}/></Animated.View><Animated.View style={[s.ecg, ecgStyle]}><ECGLine width={SW - 60} height={80}/></Animated.View></Pressable>);
}

const s = StyleSheet.create({root:{flex:1, alignItems:'center', justifyContent:'center', backgroundColor:'#0A0A0F', gap:40}, ecg:{}});
